	background-color: rgba(0, 112, 120, 0);
}

.marker-cluster-medium div {
	background-color: rgba(0, 112, 120, 1);
}

.marker-cluster-large {
	background-color: rgba(0, 112, 120, 0);
}

.marker-cluster-large div {
	background-color: rgba(0, 112, 120, 0, 1);
}

/* IE 6-8 fallback colors */
.leaflet-oldie .marker-cluster-small {
	background-color: rgb(0, 112, 120);
}

.leaflet-oldie .marker-cluster-small div {
	background-color: rgb(0, 112, 120);
}

.leaflet-oldie .marker-cluster-medium {
	background-color: rgb(0, 112, 120);
}

.leaflet-oldie .marker-cluster-medium div {
	background-color: rgb(0, 112, 120);
}

.leaflet-oldie .marker-cluster-large {
	background-color: rgb(0, 112, 120);
}

.leaflet-oldie .marker-cluster-large div {
	background-color: rgb(0, 112, 120);
}

.marker-cluster {
	background-clip: padding-box;
	border-radius: 30px;
    width: 46px !important;
    height: 46px !important;
    background: rgba(50, 50, 61, 0.7);

}

.marker-cluster-medium  {
	border-radius: 33px;
    width: 66px !important;
    height: 66px !important;
}

.marker-cluster-large {
	border-radius: 43px;
    width: 86px !important;
    height: 86px !important;
}

.marker-cluster div:hover {
	transform: scale(1.4);
    transition: all 0.5s ease;
}

.marker-cluster div {
	width: 40px;
	height: 40px;
	margin-left: 3px;
	margin-top: 3px;
	text-align: center;
	border-radius: 20px;
	font: 20px "Helvetica Neue", Arial, Helvetica, sans-serif;
    font-weight: 500;
    color: #fff;
    transition: all 0.5s ease;
}

.marker-cluster-medium div {
	width: 60px;
    height: 60px;
    border-radius: 30px;
}

.marker-cluster-large div {
	width: 80px;
	height: 80px;
    border-radius: 40px;
}

.marker-cluster span {
	line-height: 36px;
}

.marker-cluster-medium span {
	line-height: 58px;
}

.marker-cluster-large span {
	line-height: 77px;
}

