                            $('.template-cta-button', this).unwrap()
                        }
                        $('.template-cta-button', this).wrap('<div class="column-full"></div>')
                    }
                }

                $('.template-cta-button', this).each(function () {
                    if ($(this).height() > maxHeight) {
                        maxHeight = $(this).height();
                    }
                });
