html, body {
  height: auto !important;
  min-height: 0 !important;
  width: 1170px;
}
@page {
  size: 330mm 427mm;
  margin: 14mm;
}
#skiptocontent,
#header .top-header,
#header .logo-bar,
.top-header-nav,
.hamburger-container,
.search-bar,
div[role=contentinfo],
#block-barnet-council-breadcrumbs,
#block-barnet-council-local-tasks,
.addtoany_list,
.search-filters-mobile,
.page-rating,
.glossary-container,
.footer-content {
  display: none;
}
.featured-consultations{
  display: block!important;
  width: 100%;
}
#header {
  padding: 0 15px;
  background: none;
}
#header .logo-bar-print {
  display: block;
}
a {
  color: rgb(0, 118, 134);
  font-weight: 400;
  text-decoration: underline;
}
* {
  -webkit-print-color-adjust: exact !important;   /* Chrome, Safari */
  color-adjust: exact !important;                 /*Firefox*/
}

/* Homepage overrides */
.owl-carousel .owl-nav,
.owl-carousel .owl-dots {
  display: none;
}
.owl-carousel .owl-stage,
.owl-carousel .owl-item {
  float: none;
  width: 100% !important;
  transform: translate3d(0, 0px, 0px) !important;
}
.owl-carousel .owl-slide img{
  display: none;
}
.owl-carousel .owl-slide .slide-content {
  height: auto;
  padding: 60px 0;
  background: none;
}
.owl-carousel .owl-slide .slide-content h2,
.owl-carousel .owl-slide .slide-content p {
  color: #fff;
  text-shadow: 0 2px 4px rgba(0, 0, 0, 0.5);
  margin-left: 30px;
}
.owl-carousel .owl-slide .slide-content a {
  margin-left: 30px;
}
.owl-carousel .owl-item, .owl-carousel .owl-item.active{
  display: block;
}
.owl-carousel .owl-item .owl-slide{
  display: block;
}

/* Results */
.search-results .result {
  clear: both;
  width: 100%;
}
.search-results .result .result-event-date,
.search-results .result .result-image {
  float: left;
  margin-right: 0px;
  width: 200px;
}
.search-results .result .result-content {
  width: 100%;
  float: left;
}

.suggest-event-block{
  display: none;
}

/* Basic pages */
.paragraph--type--call-to-action a{
  width: auto;
}
.share-icons{
  display: none;
}
